I think it would be convenient to be able to embed Jupyter widgets in a [Vue](https://vuejs.org/) app, because Vue is a progressive web framework accessible to non specialists, for instance in the simple context of [Vuepress](https://vuepress.vuejs.org/) to write documentation.

I looked around and did not find anything on the topic.

So here is a Vue blueprint of how it could be made available to users.  
Consider it the equivalent of the ipywidget official doc for [embedding in a standalone html file](https://ipywidgets.readthedocs.io/en/latest/embedding.html#python-interface). 

Below are 3 files replacing those you get from the [vue-cli](https://cli.vuejs.org/) if you follow the instructions in [this page.](https://cli.vuejs.org/guide/creating-a-project.html):
+ App.vue
+ components/HelloWorld.vue
+ components/JupyterWidgetRenderer.vue (actually this one must be added)

I suspect a specific `embed.js` other than [`embed-amd.js`](https://unpkg.com/@jupyter-widgets/html-manager/dist/embed-amd.js) should be used.  
If it is mildly difficult, I am very interested in tips.  
If this is really advanced given the current embedding mechanism, please let me know.  


Files:
+ **App.vue**
```vue
<template>
  <div id='app'>
    <img src='./assets/logo.png'>
    <HelloWorld :title="title"/>
    <JupyterWidgetRenderer 
    :viewref="viewref"
    :state="state"
    />
  </div>
</template>

<script>
import HelloWorld from './components/HelloWorld.vue';
import JupyterWidgetRenderer from './components/JupyterWidgetRenderer.vue';

export default {
    name: 'app',
    components: {
        HelloWorld,
        JupyterWidgetRenderer,
    },
    data() {
        return {
            title: 'Embedding Jupyter Widgets in Vue',
            viewref: [
                '{"version_major": 2, "version_minor": 0, "model_id": "26ddc1e648984419a15812a72cf88609"}',
                '{"version_major": 2, "version_minor": 0, "model_id": "b72564dca1a94e238aa95025aa86f6e3"}',
            ],
            state: '{"version_major": 2, "version_minor": 0, "state": {"26ddc1e648984419a15812a72cf88609": {"model_name": "IntSliderModel", "model_module": "@jupyter-widgets/controls", "model_module_version": "1.2.0", "state": {"_dom_classes": [], "layout": "IPY_MODEL_290380900f8246188291aca69ceb0002", "max": 200, "style": "IPY_MODEL_3cc39c84b23a4daaa7f5f2fabb7e2890", "value": 100}}, "290380900f8246188291aca69ceb0002": {"model_name": "LayoutModel", "model_module": "@jupyter-widgets/base", "model_module_version": "1.0.0", "state": {}}, "3cc39c84b23a4daaa7f5f2fabb7e2890": {"model_name": "SliderStyleModel", "model_module": "@jupyter-widgets/controls", "model_module_version": "1.2.0", "state": {}}, "b72564dca1a94e238aa95025aa86f6e3": {"model_name": "IntSliderModel", "model_module": "@jupyter-widgets/controls", "model_module_version": "1.2.0", "state": {"_dom_classes": [], "layout": "IPY_MODEL_d27736fa24c0402885f5238827df698b", "style": "IPY_MODEL_fb2b1015b40540c7b3783b673c8f6a51", "value": 40}}, "d27736fa24c0402885f5238827df698b": {"model_name": "LayoutModel", "model_module": "@jupyter-widgets/base", "model_module_version": "1.0.0", "state": {}}, "fb2b1015b40540c7b3783b673c8f6a51": {"model_name": "SliderStyleModel", "model_module": "@jupyter-widgets/controls", "model_module_version": "1.2.0", "state": {}}}}',
        };
    },
};
</script>

